    quality = "gold"
    dependencies = [SilverA, SilverB]

def gather_dependencies(obj, dependants):
    if obj.dependencies is not None:
        for dep in obj.dependencies:
            dependants[dep.name] = dep.__class__.__name__
            gather_dependencies(dep, dependants)

my_gold = Gold()
