class grandparent:
    def __init__(self):
        pass
    def __str__(self):
        return f'grandparent'

class parent(grandparent):
    def __init__(self):
        pass
    def __str__(self):
        return f'{super().__str__()},parent'


class child(parent):
    def __init__(self):
        pass
    def __str__(self):
        return f'{super().__str__()},child'
```


In this case if I make an object from `child` class, after printing it I see :

```Python
